import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Check if input length exceeds buffer size
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        byte[] buffer = new byte[10];
        Arrays.fill(buffer, (byte) 0); // Fill buffer with zeros

        // Copy input to buffer
        System.arraycopy(input.getBytes(), 0, buffer, 0, Math.min(input.length(), buffer.length));

        System.out.println("Input: " + new String(buffer).trim()); // Trim excess zeros

    }
}

### Explanation:
취약유형: Buffer Overflow
